using System.Collections; using System.Collections.Generic; using UnityEngine; public class EnemyMovemnt : MonoBehaviour { Rigidbody2D rb; Animator a1; void Start() { rb = gameObject.GetComponent<Rigidbody2D>(); a1 = gameObject.GetComponent<Animator>(); } void Update() { rb.velocity = new Vector2(0, -4); } void OnCollisionEnter2D(Collision2D collision) { if (collision.gameObject.CompareTag("Bullet")) { a1.SetBool("bomb", true); Destroy(gameObject); } else if(collision.gameObject.CompareTag("Enemy")) { Destroy(gameObject); } } }